LEGACY_HTML = True  # 既存HTMLを保持（再アセンブル禁止）
TITLE = 'リフォーム費用計算【無料】キッチン・浴室・外壁の相場が分かる'
DESCRIPTION = 'リフォーム箇所・広さ・グレードを選択して費用相場を無料シミュレーション。補助金情報も掲載。'
JS_CODE = 'var reformParts = [\n  { key:"kitchen", emoji:"🍳", name:"キッチン", low:800000, high:2000000, subsidy:true, subsidyNote:"省エネ設備への交換で「子育てエコホーム支援事業」補助対象の場合あり" },\n  { key:"bath", emoji:"🛁", name:"浴室・バス", low:700000, high:1800000, subsidy:false, subsidyNote:"" },\n  { key:"toilet", emoji:"🚽", name:"トイレ", low:100000, high:400000, subsidy:true, subsidyNote:"節水型トイレへの交換で補助金対象の場合あり" },\n  { key:"floor", emoji:"🪵", name:"床・壁（内装）", low:200000, high:800000, subsidy:false, subsidyNote:"" },\n  { key:"exterior", emoji:"🏚️", name:"外壁塗装", low:800000, high:2000000, subsidy:false, subsidyNote:"" },\n  { key:"roof", emoji:"🏠", name:"屋根修繕", low:500000, high:1500000, subsidy:false, subsidyNote:"" },\n  { key:"window", emoji:"🪟", name:"窓・断熱", low:200000, high:800000, subsidy:true, subsidyNote:"断熱窓への交換は「先進的窓リノベ事業」補助金対象（最大200万円）" },\n  { key:"barrier", emoji:"♿", name:"バリアフリー化", low:300000, high:1200000, subsidy:true, subsidyNote:"介護保険「住宅改修費」最大20万円の支給あり（要介護認定者対象）" }\n];\n\nvar selected = {};\n\nfunction init() {\n  var c = document.getElementById(\'parts-container\');\n  reformParts.forEach(function(p) {\n    var btn = document.createElement(\'button\');\n    btn.className = \'part-btn\';\n    btn.innerHTML = \'<span>\'+p.emoji+\'</span><span>\'+p.name+\'</span>\';\n    btn.dataset.key = p.key;\n    btn.onclick = function() {\n      if(selected[p.key]) { delete selected[p.key]; btn.classList.remove(\'selected\'); }\n      else { selected[p.key]=true; btn.classList.add(\'selected\'); }\n    };\n    c.appendChild(btn);\n  });\n}\n\nfunction calculate() {\n  if(Object.keys(selected).length===0) {\n    alert(\'リフォームしたい箇所を1つ以上選択してください\');\n    return;\n  }\n\n  var houseType = document.getElementById(\'house-type\').value;\n  var years = document.getElementById(\'years\').value;\n  var yearsMult = { new:1.0, mid:1.1, old:1.2, \'very-old\':1.35 }[years];\n  var houseMult = houseType===\'house\' ? 1.0 : 0.8;\n\n  var totalLow = 0, totalHigh = 0;\n  var breakdown = [];\n  var subsidies = [];\n\n  reformParts.forEach(function(p) {\n    if(selected[p.key]) {\n      var low = Math.round(p.low * yearsMult * houseMult / 10000) * 10000;\n      var high = Math.round(p.high * yearsMult * houseMult / 10000) * 10000;\n      totalLow += low;\n      totalHigh += high;\n      breakdown.push({ name:p.emoji+\' \'+p.name, low:low, high:high });\n      if(p.subsidy && p.subsidyNote) { subsidies.push(p.subsidyNote); }\n    }\n  });\n\n  document.getElementById(\'r-total-low\').textContent = \'約\'+Math.round(totalLow/10000)+\'万円〜\';\n  document.getElementById(\'r-total-range\').textContent = \'高い場合 \'+Math.round(totalHigh/10000)+\'万円まで\';\n\n  var bd = document.getElementById(\'breakdown\');\n  bd.innerHTML = \'\';\n  breakdown.forEach(function(b) {\n    var div = document.createElement(\'div\');\n    div.className = \'flex justify-between text-sm border-b pb-2\';\n    div.innerHTML = \'<span class="text-gray-700">\'+b.name+\'</span><span class="font-bold">\'+Math.round(b.low/10000)+\'〜\'+Math.round(b.high/10000)+\'万円</span>\';\n    bd.appendChild(div);\n  });\n\n  var subEl = document.getElementById(\'subsidies\');\n  if(subsidies.length>0) {\n    subEl.innerHTML = subsidies.map(function(s){ return \'<div class="flex gap-1">✅ \'+s+\'</div>\'; }).join(\'\');\n  } else {\n    subEl.innerHTML = \'<div class="text-gray-500">現在選択中の箇所では主要補助金の対象外の可能性があります</div>\';\n  }\n\n  document.getElementById(\'results\').style.display=\'block\';\n  document.getElementById(\'affiliate-section\').style.display=\'block\';\n  document.getElementById(\'results\').scrollIntoView({behavior:\'smooth\'});\n}\n\ninit();'
